mapper.insert:
/** CmmtAuthorityRoleDao.insert */
insert into cmmt_authority_role (
	authority_id
	,role_id
	,creator_id
	,created_dt
) values (
	#{authorityId}
	,#{roleId}
	,#{creatorId}
	,#{createdDt}
)

/** CmmtAuthorityRoleDao.insertList */
insert into cmmt_authority_role (
	authority_id
	,role_id
	,creator_id
	,created_dt
) values

	(
		#{item.authorityId}
		,#{item.roleId}
		,#{item.creatorId}
		,#{item.createdDt}
	)

mapper.delete:
/** CmmtAuthorityRoleDao.deleteAuthorityId */
delete from
	cmmt_authority_role
where
	authority_id = #{authorityId}
